BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?dep ?clientName ?supplierName WHERE {
  ?elem vocab:NamedElement_name ?elemName .
  FILTER(CONTAINS(LCASE(STR(?elemName)), LCASE("Procedure Executive")))
  {
    ?elem vocab:Dependency_client ?dep .
    OPTIONAL { ?dep vocab:NamedElement_name ?clientName }
    ?elem vocab:Dependency_supplier ?sup .
    OPTIONAL { ?sup vocab:NamedElement_name ?supplierName }
  }
  UNION
  {
    ?dep vocab:Dependency_client ?elem .
    ?dep vocab:Dependency_supplier ?sup .
    OPTIONAL { ?dep vocab:NamedElement_name ?clientName }
    OPTIONAL { ?sup vocab:NamedElement_name ?supplierName }
  }
}
LIMIT 50

